const lib = global.get('lib');
if (!lib || !lib.telemetry || typeof lib.telemetry.handleTelemetryMessage !== 'function') {
  node.status({ fill: 'red', shape: 'ring', text: 'telemetry API missing' });
  return [null, null, { payload: { error: 'TELEMETRY_API_MISSING' } }];
}

const telemetry = lib.telemetry;
const equipmentId = 'Smoke.CalcConst';
const state = flow.get('calcConstantTelemetryState') || telemetry.createTelemetryRuntimeState();
const incoming = msg.payload && typeof msg.payload === 'object' && !Array.isArray(msg.payload)
  ? { ...msg, ...msg.payload }
  : msg;

const asNodeRedMsg = (value) => {
  if (value == null) return null;
  if (typeof value === 'object' && !Array.isArray(value) && Object.prototype.hasOwnProperty.call(value, 'payload')) {
    return value;
  }
  return { payload: value };
};

const envCfg = {
  CompilerMaxQty: 120,
  CompilerMaxSpan: 80,
  CompilerMaxHole: 4,
  PollFastMs: 250,
  PollNormalMs: 1000,
  PollSlowMs: 5000,
  MAX_IN_FLIGHT: 4,
  REQUEST_TIMEOUT_MS: 1500,
  MODBUS_ZERO_BASED: false,
  JITTER_MS: 0,
  RESPECT_TAG_CLAMP: true,
  SCALE_CLAMP_DEFAULT: false,
  SKIP_EMPTY_SAMPLES: false
};

try {
  const result = telemetry.handleTelemetryMessage(
    incoming,
    envCfg,
    state,
    (o1, o2, o3) => node.send([asNodeRedMsg(o1), asNodeRedMsg(o2), asNodeRedMsg(o3)])
  );

  flow.set('calcConstantTelemetryState', result.state);
  const activePlan = result.state && result.state.readPlans && result.state.readPlans[equipmentId];
  if (activePlan) {
    flow.set('calcConstantPlan', activePlan);
  }

  const statusText = incoming.cmd || (incoming._reader ? 'reply' : 'start');
  node.status({ fill: 'green', shape: 'dot', text: statusText });

  return [asNodeRedMsg(result.out1), asNodeRedMsg(result.out2), asNodeRedMsg(result.out3)];
} catch (err) {
  node.status({ fill: 'red', shape: 'ring', text: 'runtime threw' });
  return [null, null, { payload: { error: String(err) } }];
}

const samples = Array.isArray(msg.payload) ? msg.payload : [];
const snapshot = flow.get('calcConstantSnapshot') || {};
const plan = flow.get('calcConstantPlan') || {};

for (const sample of samples) {
  if (!sample || !sample.tagID) continue;
  snapshot[sample.tagID] = {
    value: sample.value,
    timestamp: sample.timestamp || Date.now(),
    alarm: sample.alarm || 'No',
    supportingTag: sample.supportingTag || 'No'
  };
}

flow.set('calcConstantSnapshot', snapshot);

const pick = (ids) => {
  const out = {};
  for (const id of ids) {
    if (Object.prototype.hasOwnProperty.call(snapshot, id)) {
      out[id] = snapshot[id];
    }
  }
  return out;
};

const constantTagIDs = Array.isArray(plan.constants) ? plan.constants.map((item) => item.tagID) : [];
const calcTagIDs = Array.isArray(plan.calcs) ? plan.calcs.map((item) => item.tagID) : [];
const report = {
  ts: Date.now(),
  tagCount: Object.keys(snapshot).length,
  tags: snapshot,
  constants: pick(constantTagIDs),
  calcs: pick(calcTagIDs),
  constantTagIDs,
  calcTagIDs
};

flow.set('calcConstantLastReport', report);
msg.payload = report;
return msg;

const state = flow.get('calcConstantTelemetryState') || {};
const plan = state.readPlans && state.readPlans['Smoke.CalcConst'];
if (!plan) {
  return [null, { payload: { error: 'missing-readplan' } }];
}

const blockIdx = plan.blocks.findIndex((block) =>
  Array.isArray(block.map) && block.map.some((item) => item.tagID === 'RAW_POWER')
);
if (blockIdx < 0) {
  return [null, { payload: { error: 'raw-power-block-missing' } }];
}

return [{
  _reader: { equipmentId: plan.equipmentId, blockIdx },
  payload: [Number(msg.payload) & 0xffff]
}, null];

const state = flow.get('calcConstantTelemetryState') || {};
const plan = state.readPlans && state.readPlans['Smoke.CalcConst'];
if (!plan) {
  return [null, { payload: { error: 'missing-readplan' } }];
}

const blockIdx = plan.blocks.findIndex((block) =>
  Array.isArray(block.map) && block.map.some((item) => item.tagID === 'SCALE_EXP')
);
if (blockIdx < 0) {
  return [null, { payload: { error: 'scale-exp-block-missing' } }];
}

let raw = Number(msg.payload);
if (!Number.isFinite(raw)) {
  return [null, { payload: { error: 'scale-exp-invalid', value: msg.payload } }];
}
if (raw < 0) {
  raw = 0x10000 + raw;
}

return [{
  _reader: { equipmentId: plan.equipmentId, blockIdx },
  payload: [raw & 0xffff]
}, null];
